import React, { useContext, useReducer, useState } from "react";
import { userContext } from "../App";
import TaskForm from "./TaskForm";

const TaskItem = React.memo(function TaskItem ( { task, toggleTaskCompletion } ) {
    const {tasks, setTasks} = useContext(userContext);
    const { displayForm, setDisplayForm } = useState(false);

    const reducer = (state, action) => {
        switch (action.type) {
            case 'edit':
                editTask(action.payload);
                return state;
            case 'delete':
                deleteTask(action.payload);
                return state;
            default:
                return state;
        }
    };
    const initialState = { count: 0 };
    const { count, dispatch } = useReducer(reducer, initialState);

    function deleteTask(taskId) {
        setTasks(tasks.filter(t => t.id !== taskId));
    }   

    function editTask() {
        se
    }
    return (
        <li className={`task-item ${task.completed ? 'completed' : ''}`} 
            onDoubleClick={() => editTask(task.id)}>
            <input 
                type="checkbox" 
                className="task-checkbox"
                checked={task.completed}
                onChange={() => toggleTaskCompletion(task.id)}
            />
            <div className="task-content">
                <h3 className="task-title">{task.title}</h3>

                <div className="task-meta">
                    <span className={`task-priority ${task.priority}`}>
                        {task.priority === 'high' && '🔴 '}
                        {task.priority === 'medium' && '🟡 '}
                        {task.priority === 'low' && '🟢 '}
                        {task.priority}
                    </span>


                    <span className="badge-secondary" style={{ 
                        padding: 'var(--spacing-xs) var(--spacing-sm)',
                        borderRadius: 'var(--radius-sm)',
                        fontSize: '0.75rem',
                        background: 'var(--bg-tertiary)',
                        border: '1px solid var(--border)'
                    }}>
                        {task.createdAt}
                    </span>
                </div>
            </div>
            <button onClick={editTask}>✏️</button>
            <button className="btn btn-danger" onClick={deleteTask}>
                🗑️
            </button>
            <TaskForm className="card-center" displayForm={displayForm} setDisplayForm={setDisplayForm} action="edit" taskTEdt={task.id} ></TaskForm>
        </li>
    )
});

export default TaskItem;
